var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>각 소대, 상황 보고.</color>","JPN":"<color=#ffd34c>各小隊、状況を報告しろ。</color>","ENG":"<color=#ffd34c>All squads, report.</color>","TWN":"<color=#ffd34c>各小隊，報告情況。</color>"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"카나리아 스쿼드, 지정 초소에서 대기 중. 이상 없음.","JPN":"カナリア・スクワッド、指定の監視所にて待機中。異常なし。","ENG":"This is Canary Squad, standing by at the designated lookout. Nothing out of the ordinary.","TWN":"金絲雀小隊，正在指定哨所待命。無異常。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하아…. 안 나타나네.","JPN":"はあ……現れないな。","ENG":"*Sigh*... Nothing.","TWN":"嘖……什麼也沒有嘛。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게요. 공개 회선은 아까부터 계속 시끄러운데.","JPN":"そうね。公開回線はさっきからずっとうるさいのに。","ENG":"Yeah. The open lines have been sounding pretty busy for a while now.","TWN":"沒錯，不過公用頻道從剛才就一直很吵。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이름이 잘 알려진 태스크포스들도 몇 군데 당했나 봐요.","JPN":"有名なタスクフォースもいくつかやられてるみたいね。","ENG":"It seems that even some renowned TASKFORCEs were taken down.","TWN":"好像幾個有名的特遣勢力在一些地方也陷入苦戰。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"끄응. 어째 돌아가는 상황이 심상치 않은데.","JPN":"ぐぬぬ。なんだか不気味な状況だな。","ENG":"Ugh. I have a bad feeling about this.","TWN":"呃，怎麼感覺情況不太妙。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하늘 좀 봐. 차원 함선까지 동원했어.","JPN":"空を見てみろよ。次元艦船まで動員されてる。","ENG":"Look at the sky. They even brought out dimensional ships.","TWN":"你看天空，連次元艦船都出動了。"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"대체 뭐 하는 수배잔데 이 난리래. 이상한 약 먹은 S급 카운터라도 되나.","JPN":"これほどの大騒ぎになるなんて、手配犯はいったいどんな奴なんだ？　変な薬でもやってるSランクカウンターとか？","ENG":"What kind of felon is causing this much chaos? Maybe it's a Grade S Counter on drugs or something.","TWN":"這個通緝犯到底是何方神聖？搞得大家人仰馬翻的。難道是吃了禁藥的S級制裁者？"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카! 전방에 미확인 비행체 확인!","JPN":"ライカ！　前方に未確認飛行物体を確認！","ENG":"Laika! UFO, straight ahead!","TWN":"萊卡！前方發現不明飛行物！"},"stage":{"bg":"CCN_SHIP","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"착지 성공. 도착지까지의 이동 경로를 재설정합니다.","JPN":"着地成功。到着地までの移動経路を再設定します。","ENG":"Landing successful. Rerouting.","TWN":"著陸成功。重新設定前往目的地的移動路線。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"사, 사람…? 하지만 방금 건물 뒤에서 날아왔는데?","JPN":"に、人間……？　でも、今建物の後ろから飛んできたけど？","ENG":"A-a person...? But she just flew in from behind that building...","TWN":"這，這傢伙是人嗎…？她剛才是從大樓後面飛過來的……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 사이코 꼬맹이. 너 혹시 배 다른 언니 있었냐.","JPN":"おい、サイコガキ。ひょっとして腹違いのお姉さんでもいた？","ENG":"Hey, psycho kid. I didn't know you had a sister from another mother.","TWN":"喂，小瘋子，你有沒有什麼失散多年的姊姊？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이 상황에 그게 무슨 헛소리예요!","JPN":"この状況で何を言ってるのよ！","ENG":"W-what are you talking about?!","TWN":"都什麼時候了，你在胡說什麼！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니. 쟤 패션 센스가 너만큼 정신 나간 것 같아서.","JPN":"いや。あいつのファッションセンスが同じくらいイカレてる気がして。","ENG":"Well. Just seems like her taste in clothes is almost as crazy as you are.","TWN":"沒有啦，我看她的穿衣品味和你一樣有意思呢。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으… 좀 품격 있는 농담을 할 수는 없어요? 저질.","JPN":"うう……もうちょっとセンスのある冗談言えないの？　最低。","ENG":"Ngh... Can't you come up with better jokes? That's really low.","TWN":"呃……不能開別的玩笑嗎？不好笑！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};